class Node:
    def __init__(self, label):
        self.label = label

    def __str__(self):
        return self.label


def make_set(x):
    """initializes disjoint set for object x"""
    x.parent = x
    x.rank = 0


def union_set(x, y):
    """merge the set x and set y to form one set

    :param x: Node x
    :param y: Node y
    """
    x_root = find(x)
    y_root = find(y)
    if x_root.rank > y_root.rank:
        y_root.parent = x_root
    elif x_root.rank < y_root.rank:
        x_root.parent = y_root
    elif x_root != y_root:  # Unless x and y are already in same set, merge them
        y_root.parent = x_root
        x_root.rank = x_root.rank + 1


def find(x):
    """returns representative object of the set containing x
    :param x: the node on which you want to find the representative
    :return: the representative node of x
    """
    if x.parent == x:
        return x
    x.parent = find(x.parent)
    return x.parent
